1069→void ALFPTacticsPlayerController::StartPlacingUnit(int32 PartyIndex)
1070→{
1071→    // 如果正在放置其他单位，先取消
1072→    if (bIsPlacingUnit)
1073→    {
1074→        CancelPlacing();
1075→    }
1076→
1077→    ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
1078→    if (!GI || !GI->UnitRegistry) return;
1079→    if (!GI->PartyUnits.IsValidIndex(PartyIndex)) return;
1080→
1081→    // 如果该单位已经放置，先拾起
1082→    if (DeployedUnits.IsValidIndex(PartyIndex) && DeployedUnits[PartyIndex])
1083→    {
1084→        PickupDeployedUnit(DeployedUnits[PartyIndex]);
1085→    }
1086→
1087→    const FLFPUnitEntry& Entry = GI->PartyUnits[PartyIndex];
1088→    TSubclassOf<ALFPTacticsUnit> UnitClass = GI->UnitRegistry->GetUnitClass(Entry.TypeID);
1089→    if (!UnitClass) return;
1090→
1091→    // 在鼠标位置生成预览单位
1092→    FVector UnitSpawnLoc = FVector(0, 0, 50.f);
1093→    FActorSpawnParameters SpawnParams;
1094→    PlacingUnitPreview = GetWorld()->SpawnActor<ALFPTacticsUnit>(UnitClass, UnitSpawnLoc, FRotator::ZeroRotator, SpawnParams);
1095→
1096→    if (PlacingUnitPreview)
1097→    {
1098→        PlacingUnitPreview->Affiliation = EUnitAffiliation::UA_Player;
1099→        PlacingUnitPreview->UnitTypeID = Entry.TypeID;
1100→        PlacingUnitPreview->UnitTier = Entry.Tier;
1101→    }
1102→
1103→    PlacingPartyIndex = PartyIndex;
1104→    bIsPlacingUnit = true;
1105→
1106→    if (DeploymentWidget)
1107→    {
1108→        DeploymentWidget->MarkUnitSelecting(PartyIndex);
1109→    }
1110→
1111→    UE_LOG(LogTemp, Log, TEXT("开始放置单位 %s（索引 %d）"), *Entry.TypeID.ToString(), PartyIndex);
1112→}
1113→
1114→void ALFPTacticsPlayerController::PlaceUnit(ALFPHexTile* Tile)
1115→{
1116→    if (!Tile || !PlacingUnitPreview || PlacingPartyIndex < 0) return;
1117→
1118→    // 放置到格子上
1119→    FVector TileLocation = Tile->GetActorLocation() + FVector(0, 0, 50.f);
1120→    PlacingUnitPreview->SetActorLocation(TileLocation);
1121→    PlacingUnitPreview->SetCurrentCoordinates(Tile->GetCoordinates());
1122→
1123→    // 更新格子占用
1124→    Tile->SetIsOccupied(true);
1125→    Tile->SetUnitOnTile(PlacingUnitPreview);
1126→
1127→    // 记录到已布置列表
1128→    if (DeployedUnits.IsValidIndex(PlacingPartyIndex))
1129→    {
1130→        DeployedUnits[PlacingPartyIndex] = PlacingUnitPreview;
1131→    }
1132→
1133→    // 更新 UI
1134→    if (DeploymentWidget)
1135→    {
1136→        DeploymentWidget->MarkUnitPlaced(PlacingPartyIndex, true);
1137→    }
1138→
1139→    UE_LOG(LogTemp, Log, TEXT("放置单位到格子 (%d, %d)"), Tile->GetCoordinates().Q, Tile->GetCoordinates().R);
1140→
1141→    // 重置放置状态
1142→    PlacingUnitPreview = nullptr;
1143→    PlacingPartyIndex = -1;
1144→    bIsPlacingUnit = false;
1145→}
1146→
1147→void ALFPTacticsPlayerController::CancelPlacing()
1148→{
1149→    if (PlacingUnitPreview)
1150→    {
1151→        PlacingUnitPreview->Destroy();
1152→        PlacingUnitPreview = nullptr;
1153→    }
1154→
1155→    PlacingPartyIndex = -1;
1156→    bIsPlacingUnit = false;
1157→}
1158→
1159→void ALFPTacticsPlayerController::PickupDeployedUnit(ALFPTacticsUnit* Unit)
1160→{
1161→    if (!Unit) return;
1162→
1163→    // 找到对应的 PartyIndex
1164→    int32 FoundIndex = DeployedUnits.Find(Unit);
1165→    if (FoundIndex == INDEX_NONE) return;
1166→
1167→    // 清除格子占用
1168→    ALFPHexTile* OldTile = Unit->GetCurrentTile();
1169→    if (OldTile)
1170→    {
1171→        OldTile->SetIsOccupied(false);
1172→        OldTile->SetUnitOnTile(nullptr);
1173→    }
1174→
1175→    // 设置为跟随鼠标的预览
1176→    PlacingUnitPreview = Unit;
1177→    PlacingPartyIndex = FoundIndex;
1178→    bIsPlacingUnit = true;
1179→
1180→    // 清除已布置记录
1181→    DeployedUnits[FoundIndex] = nullptr;
1182→
1183→    // 更新 UI
1184→    if (DeploymentWidget)
1185→    {
1186→        DeploymentWidget->MarkUnitPlaced(FoundIndex, false);
1187→    }
1188→
1189→    UE_LOG(LogTemp, Log, TEXT("拾起已放置的单位（索引 %d）"), FoundIndex);
1190→}
1191→
1192→void ALFPTacticsPlayerController::ConfirmDeployment()
1193→{
1194→    if (!bIsInDeployment) return;
1195→
1196→    // 取消高亮
1197→    for (ALFPHexTile* Tile : PlayerSpawnTiles)
1198→    {
1199→        if (Tile)
1200→        {
1201→            Tile->SetMovementHighlight(false);
1202→        }
1203→    }
1204→    PlayerSpawnTiles.Empty();
1205→
1206→    // 移除布置 UI
1207→    if (DeploymentWidget)
1208→    {
1209→        DeploymentWidget->OnUnitSelected.RemoveDynamic(this, &ALFPTacticsPlayerController::StartPlacingUnit);
1210→        DeploymentWidget->OnConfirmPressed.RemoveDynamic(this, &ALFPTacticsPlayerController::ConfirmDeployment);
1211→        DeploymentWidget->RemoveFromParent();
1212→    }
1213→
1214→    bIsInDeployment = false;
1215→    bIsPlacingUnit = false;
1216→
1217→    // 通知 TurnManager 结束布置阶段
1218→    ALFPTurnManager* TurnManager = GetTurnManager();
1219→    if (TurnManager)
1220→    {
1221→        TurnManager->EndDeploymentPhase();
1222→    }
1223→
1224→    UE_LOG(LogTemp, Log, TEXT("布置确认，进入战斗"));
1225→}
